DROP TABLE IF EXISTS `chat_conversations`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `chat_conversations` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT 'Тх╝Т░│уўйID',
  `conversation_uuid` varchar(36) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Тх╝Т░│уўйUUID',
  `user_id` bigint DEFAULT NULL COMMENT 'жљбсёдтЪЏID',
  `scenic_id` bigint DEFAULT NULL COMMENT 'жЈЁЬѕџт░»ID',
  `last_message` text COLLATE utf8mb4_unicode_ci COMMENT 'жЈѕРѓгжЇџт║ЮуФ┤жЈЅРёЃуДижјГ?,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT 'жЇњТХўу╝ЊжЈЃтаЋТБ┐',
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT 'жЈЄтГўТЪіжЈЃтаЋТБ┐',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_conversation_uuid` (`conversation_uuid`),
  KEY `idx_user_id` (`user_id`),
  KEY `idx_scenic_id` (`scenic_id`),
  CONSTRAINT `fk_conversation_scenic` FOREIGN KEY (`scenic_id`) REFERENCES `scenic_spots` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_conversation_user` FOREIGN KEY (`user_id`) REFERENCES `users` (`user_id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=67 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='жЉ▒тЕѓсЂЅТх╝Т░│уўйуљЏ?;
