INSERT INTO `chat_messages` (`id`, `conversation_id`, `role`, `content`, `created_at`) VALUES (1,1,'user','ТхБуі▓сѓй','2025-10-11 06:03:17'),(2,1,'assistant','жј«сёЦсѓйжћЏт▒ЙтъюжЈёЬѕЏТФцжЉ│УЌЅтДфжјхтгеРѓгтѓЏтЂЇуњЄУЙЙу┤░ТхБуі▓сѓй','2025-10-11 06:03:17'),(3,2,'user','ТхатЕѓсЂЅТЙХРЋѓуџхжјгт║Юу«ъжЈЇ?,'2025-10-11 06:03:26'),(4,2,'assistant','жј«сёЦсѓйжћЏт▒ЙтъюжЈёЬѕЏТФцжЉ│УЌЅтДфжјхтгеРѓгтѓЏтЂЇуњЄУЙЙу┤░ТхатЕѓсЂЅТЙХРЋѓуџхжјгт║Юу«ъжЈЇ?,'2025-10-11 06:03:26'),(5,3,'user','ТхБуі▓сѓй','2025-10-11 06:12:05'),(6,3,'assistant','ТхБуі▓сѓйжћЏСй╣Т╣ЂТхаРѓгТХћтаЪтъюжЇЎЬѕЎС║њућ»Ьє╗уХўжљетІФТѓДжћЏуЄёуЁњ?,'2025-10-11 06:12:07'),(7,4,'user','ТхатЕѓсЂЅТЙХРЋѓуџхжјгт║Юу«ъжЈЇ?,'2025-10-11 06:12:11'),(8,4,'assistant','жј┤ТѕъТБцтеЅТЏАт╣ЈжЇЎТаетЂЇжјхРѓгжЇдсёДТ«ЉжЇЈУюѓуХІТхБтХЄуќєжЇют▒йуќёжЈЃУи║сЂЅтДўТќЙС┐іжјГЬѕўРѓгтѓџу╝ЊуњЂЬєйтЂЇжЈїсЃДТ╣ЁУц░Тњ│Т╣┤жљетІФсЂЅтДўТЌѕЬЋЕжјХсЃЦу░▓жљбсёдтъеу╝ЃТѕауЈ»жћЏт▒йЬЏДТХЊЬЁъТхЌтДўТЌЄУќёуЂъРѓгжієСйИсЂЅтДўТЌѕРѓгТ░ЦРѓгСйИРЁиТЮЕуЉ░сЂЅтДўТЌѓуЊЉжћЏт▒╝С║њжЉЙт│░тйЄжЇЉтЌЎРђўжљетІФсЂЅтДўТЌђтёЈжЇљуѓ╣РѓгтѓџЬЏДжЈІТ╗ётЂЇжЇЏтЕЁуўћжј┤ТѕътЂЇжјхРѓгжЇдсёДТ«ЉжЇЕт║АуФХжћЏт▒ЙтъюжЇЎЬѕЎС║њжј╗ТёфуихТХЊРѓгТхюТХбРѓгТ░▒ТЋцжљетІгуЁАуњЄсѕау╝ЊуњЂЬєйтъеућ»Ьє╝тДфжј«сёцу░АуЉЎ№йЁЬЏДТхБТЏАт╣ЈжЇЎТаДуќёжЈЃУи║сЂЅтДўТќЙС┐іжјГЬѕўРѓг?,'2025-10-11 06:12:14'),(9,5,'user','жЇЈЬЁаТ┤ЈтДўу┐ау▓ќТЙХРЋЂсЂЅтДўТЌђРѓгт║Юу«ъжЈЇ?,'2025-10-11 06:12:23'),(10,5,'assistant','жј┤ЬЂЄтџджљЕЬє╝тбажћЏ?024жфъ?жЈѕтагу┤џжћЏт▒ЙтъюжЈЃуі│уАХжЉЙт│░тйЄуђ╣уѓ┤ТцѓТЙХРЋѓуџхТиЄРёЃС╝Ёжієтѓџу╝ЊуњЂЬєйтЂЇжќФТ░│у╣ЃжЈЅтєеРќЅТЙХРЋѓуџхжфътє▓тй┤Т┐АтѓЎУЁЉжЇЦУіЦуџхуњъРђ│уюгжієСйиУЁЉТЙХЬєйуџхуњъРђ│тй┤уђ╣Те╝уХЅжћЏт▒ЙтъеТхБУиеТЋцжјхтгФТ║ђТЙХРЋѓуџхТљ┤ТЌѓТЋцжћЏтаЮЬЏДТЙДсёеТіЌТЙХРЋѓуџхжієСйИтЃхТхюТѕЮсЂЅтДўТќ╗РѓгСй╣ТЋ«ТхаТе║уќѓ/т»░Ьє╗С┐іжЇЕт║АуФХжЈѕтХЁтДЪу╗ЏтцЏу┤џжЈїсЃеЬЄЌжѕЦТ╗ЃтЈџжљЕТе╗ТїЅжѕЦТ┐Ёу▓ќТЙХРЋЃТ«Љуђ╣уѓ┤ТцѓТЙХРЋѓуџхжј»тЉГтќїжієС┐Њn\nТХЊтХѕу╣Ѓжј┤ТѕЮтй▓ТхасЃЦТєАуњЄтцІтЂЇжћЏ? \nжЇЈЬЁаТ┤ЈтДўу┐ауХЁТхют║цтљ╣т«ИуѓхТИиуЉЌтЮЌтё┤жћЏт▒йТ┤ютДўТќ┐РѓгТгЈтЎ│жљќтДљРѓгСйИЬў┤уђЏ№йЁжњЕжЇДтЏеуџхтеЊРЋЃт«│19-22жѕЕтє┐у┤Юу╗▒уі│Т╣ЂжѕЦТ╗ђУЁЉжЇЦУЌЅтЎ│жќ«УДБРѓгТ┐Ёу«Бу╗ЅУѕгРѓгт