INSERT INTO `landing_config` (`id`, `config_key`, `config_value`, `version`, `updated_by`, `created_at`, `updated_at`) VALUES (1,'stats','[{\"id\": 1, \"label\": \"ТБ░тІгуЦ┤жЇЉтЌЎРђўжљютў░", \"suffix\": \"%\", \"target\": 96}, {\"id\": 2, \"label\": \"уЉЋтЌЎТ┤іжЈЁЬѕџт░»\", \"suffix\": \"+\", \"target\": 128}, {\"id\": 3, \"label\": \"жфътє▓ТйјжЇЮтХЁу░▓\", \"suffix\": \"ms\", \"target\": 180}]',1,NULL,'2025-10-10 08:15:06','2025-10-10 08:15:06'),(2,'features','[{\"id\": 1, \"icon\": \"ждЃТЋГ\", \"title\": \"жЈЁжИ┐тЁўуђ╣сѕАуЦдТБ░тІгуЦ┤\", \"description\": \"жЇЕУй░у░гLSTM-ARIMAтеБт│░Тѓјтд»Рђ│уђижћЏт▓ђу░┐жЇЉтЌЏЬЋЕте┤тгФТ╣ГжЈЅ?-30ТЙХРЋѓТФЎжЇќтЊёЬЁ╣те┤СЙђтЎ║\"}, {\"id\": 2, \"icon\": \"ждЃТцЄжћћт╗Ф", \"title\": \"уљЏт▓ђРќ╝уЉЎтІФтъЮ\", \"description\": \"AIу╗аТЦЂуАХТх╝Те║т»▓теЊТГїЬЮЇуњ║ЬѕютџјжћЏт▓ёС╝Ет»«РѓгжјисЃЦуЅГжћЏт▓ЃтдГжљфСй╣ТцѓжЌѓубХ"}, {\"id\": 3, \"icon\": \"ждЃТљ│\", \"title\": \"уђ╣уѓ┤ТцѓжЈЂуЅѕтхЂжЇњтЌўуђй\", \"description\": \"3DжЇЎЬѕЮЬЮІжЇќТаДсЂЄуЂът┐Цу┤Юуђ╣уѓ┤Тцѓжј║т▒ЙтйЎжЈЁЬѕџт░»жЇћсёдРѓгС╣Ќ"}]',1,NULL,'2025-10-10 08:15:06','2025-10-10 08:15:06'),(3,'testimonials','[{\"role\": \"ТЮЕТё»ТЃђу╝Ђт┐ЋТѓі\", \"author\": \"тДўТЮЉуЁёжЇЎсѓЅТЎБ\", \"content\": \"ТБ░тІгуЦ┤у╝ЂТњ┤уЂЅжЇЕуЃўТ╣░уњљТЮЉТѓјуђ╣уѓ║Тф»жћЏт▒йт║южЇћРЋѓтъюТхаЬёЂтйЂжЇЊтХѕуџЪжќ░тХѕуЦФтЕДТђй"}, {\"role\": \"ућ»тѓџТ║ђжјгУЇцТ┤Ѓ\", \"author\": \"тДітЉ░тД│уЂъУЙеТФЎжЇќу»Г", \"content\": \"жЈЂуЅѕтхЂТЙХЛЃуЮєт»░табТ┤┐уЉЎтѓду┤ЮтеЊуе┐ЬЁ╣ТХћує╗тЁўуђ╣уѓ┤ТцѓТхютЌџлњжЈЁЬѕџт░»жј»тЉГтќї\"}]',1,NULL,'2025-10-10 08:15:06','2025-10-10 08:15:06');
