INSERT INTO `news` (`id`, `title`, `summary`, `content`, `category`, `covers`, `scenic_id`, `author_id`, `views`, `status`, `publish_time`, `created_at`, `updated_at`, `activity_id`, `source`) VALUES (8,'жієтЕѓтЈџжљЕТе╗ТїЅжље?жѕЦТ╗ЃуЁёућ»тѓюУ▒буђ╣Т┐ѕуЁХжѕЦТ┐Њу┤њжЈёт║бу«╣тЕђтъ«Т╣┤жћЏТ░гтјцуњљтйњРѓгТХ│у┤ЮжЇдсёЦуЁёућ»тѓътЎижќГтѓъРѓгтЉ░тџюжљњтЅЂТъЪжј░тагуХќжіє?,'','жЈёт║бу«╣жЇЦУЌЅЬєЇтЕђтъ«Т╣┤жЇЈЬёђТ┤»жћЏт▒ЙТДИжЇЈЬЁаТ┤ЈтДўТЮЉуФХТХЊЬЁъуИЙжље?жѕЦТ╗ЁТЋЊжјгСй║ЬЮЮТЙДтєБРѓгТ┐ёРѓгтѓЏуиътЕбтаЪу«╣тДўТигРѓгСййТЄЋжќ«Сй╣Ьў▓уљџЬѓАугїжљюжбЂтћгтдЌсЃдЬЋджљЕтЉіТДДжј┤Тё»тЈ«жћЏт▒ЙТъЂтДЮсЃЦтЈЙТХЊЬЁеу┤ЮжЈЃсѕБтЁўжј░уєитйѕтЕђтъ«Т╣┤жљбуєИРѓгСй║Т«ЉтеЊтЉГУЈЄжЌѕТгњтЊђжћЏт▒йт╝хжЉ│УЌЅТ╣ф жѕЦТ╗ЃуЁёућ»тѓюу«њжЇЌт║ўРѓг?ТХЊ?жѕЦТ╗єтџюжљњтаЋтЎ╣уЊњ№йѓРѓг?жЌѓуБІтџюжљбтЇътъЈжј╣ЬЮгРѓгтѓъсѓГжЇџт║бТџјтДЮсЃБРѓгСйИТЄєжЈѕЬѓдтЎ╣ТцЂТёХу┤Южј┤ТаеТДИжЇЌТЏатЄйжќФтєфЬъЄжЇаЛЃТ«╗ жѕЦТ╗ЃТЃЏтДўЛђРѓгТ┐Њу┤ЮТЮЕТгЊтЎижќ«УіЦТДИжљцТЦЂтЅцжЪгЬѓбуИЙжљетІГу▓иТхБтЁЁу«БжќФтцЏуХќ','жЈЁЬѕютЂБжј║сёет┤ў',NULL,5,18,0,'published','2025-10-19 05:28:54','2025-10-19 05:28:54','2025-10-19 05:28:54',NULL,'manual'),(9,'жієтЕѓтјцуњљУДёуЪЄте┤уе┐у┤АТхБТњ╗уЇЎжћЏСй╣ТїЅжЇЕт║АтйюжЌђтЏиу┤░жљДТЃДтІЙуљЏТЦђУ┤Ежќ▓т▓Іу┤Южњўт┐ЋТйЃжЇЈЬЁаТ┤ЈтДўтГўТИХте┤ТњХТ«ЉжљЉує║С╝ђТХЊт║буџ»ТиЄТЦІуХќжіє?,'','жЇЈтХѕтъѓт»«РѓгжЈђтЅДТ«ЉтДўТЮЉуЁёжЇЎсѓЅТЎБжћЏт▒ЙТДИжЇЈЬЁаТ┤ЈтДўТЮЉти╗жЇЎтЈЅТъЃжЇќТаФТ«Љ жѕЦТ╗ёТц┐жјгСйИт┤ЦжљЌРЋЁЬЏФжѕЦТ┐ёРѓгтѓъТйџжљГУЎФТЙўуњ║ЬѕўРѓгСйИЬў▓жЇЎсѓЁу╝Њу╗ЏТѕдТЎФжЇњУЇцТйЃт«ђСй╣Т╣ђжљЦТЏАТіЌжћЏт▓ЃЬћюТЙХтГўуџ»ТиЄТЦёсђЃтЕЋТЌѓтё╣жЌѓтйњуЪъте▓С╝Ўу┤ЮжљЌуАЁтБіуЂЈт┐ЊТѓєжјйтЕЈу┤ЎТ┐АтѓютёЦжќ┐тЉФРѓгСй║уицжЉ▓тцїуЪЄжћЏтцљЬЏЙтДўТЌѓТ┤┐жќйтЕџУЊЪжЉхТЌЊу┤ЮжјхтгфС╝љжЉ╣тЊёТљДТљ┤ТЦЂТєютЕі№╝ёу░┐т«ИЛЁТ«ЉжЌѕуѓ║С╗љжљЌРЋђТгбжѕЦ№И╣Рѓг?уњДТІїу╣ўТЮЕТгЊтЎижћЏт▒╝У▒бТхБТХџРћЏуЊњтЕЃТцѓжЇЈтцЏу┤ЮТХЊРѓгу╗ћТгЈу┤Ажј░уєитйѕжЇЈЬЁаТ┤ЈтДўт»ИТ«ЉжљЉує║С╝ђтДўТќЙугїтДўТѕюу╣ћТдётЉГтДЈжћЮ?,'жЈЃтЉ«уѕХжЈђУЇцТџљ',NULL,4,19,0,'published','2025-10-19 05:29:29','2025-10-19 05:29:29','2025-10-19 05:29:29',NULL,'manual'),(10,'жієтЕЄТБиТЮЕ?жѕЦТ╗єтљ╣т«Иуѓ▓ую┐жЉ┤теЙРѓг?у╗ћсЃеуўйжћЏСйиу«цжњѓТгЈсЂЄжЉйтцітИФжћЏТ░│т┤ЈжЇўує┤РѓгСЙђЬЌЊжљбуѓ╣РѓгСй║тбйжЇдтЊёТѓЊтдЌтЌГу┤ЮжЌЁт┐ћтбюжјитХЅтЁўжЈё?жѕЦТ╗ЃсЂЅжЉ║УЙеТЙўу╗ЙЛђРѓг?ТЙХЛЁтбќжћЮуѓфРѓг?,'','уљџЬѓЦуЇЋТХЊ?жѕЦТ╗єтљ╣т«Иуѓ▓ую┐жЉ┤теЙРѓг?жљетІфу«цжњѓТгЈсЂЄжЉйтцітИФжћЏт▒ЙтдИ жѕЦТ╗ѕуЈ«уЂъУЙФт┤ЈжЇўує║Т«ЉТЮѕС╗ІТДў + ТцІт║БТЋИжЇдУЎ╣Т«Љу╗ЅТѕътдДжј░?+ жљЌЛЃТ║ђжљетІгтЂЂжљњтъЏРѓг?уђ╣т▓ђуиежЊ╗тХЁТѓјжієтѓюуЈ»жЇдсёет┤ЈжЇўуєХугѓжћЏт▒йТ│ЋжЇетг«ЬЌЊжљбжЮЏтйЙжљЌтЏЕу┤ду╝ѓТњ╣ТхєжЇћЬЪњу┤Южј┤Тё«тЁбжљЌТХџуицжј«уіхтіДжЪфУЙеЬёъжћЏт▒ЙТБцТЮѕуАЁт┤Јжљбуе┐Т╣фжљфуЁјтбажќЙтЊёуЮЇжћЏтабЬЮљжЇљЬёЂТ┤┐жЈёж╣ЃтЎЙТдЏтІ«тф┐жЉ╝Ьѓгу┤џжієтѓЏТйхТЮЕТгЊтЎижЌЄУїХТЃђжієСййТІижЈЃсЃЦтџГжЈЃсЃеТЃцжћЏт▒╝У▒бТхБТХЌуФ┤ТЙХтГўтбАТЮЕТХютџюжљбтЇът╝хТЙ╣ЬєЙуиежљетІГЬЂбуњЄТ┐ЁугўжљБт▓ІуХќ','жЈЁЬѕютЂБжј║сёет┤ў',NULL,3,16,0,'published','2025-10-19 05:30:25','2025-10-19 05:30:25','2025-10-19 05:30:25',NULL,'manual'),(11,'жієтЕѓтЈЈжфъу┐аугЅжќ▓тХєуЅ▒жљетІФТЈЕТХћТёХу┤њжљютцјтъЌжЇЦУЌЅЬєЇтдФЬєйуЂёжЇЈЬёђТ┤»жћЏТ░гтИФТ┐«тгФ№╝јжЈІТц╝РѓгСйИт┤ЋжЇЌТЦЂТИХТЙХЛёу▓джЌєЬЂёТ║ђжћЏт▒ЙтБЎжЇќтЉгуХўжЇЦТХўЬёюжљетІгТ╣Ат»░тњЃуХќжіє?,'','жњўт┐ЋТйЃ жѕЦТ╗ЃтИФТ┐«тгФ№╝јжЈІ?+ жЇЌт║Ат┤АжЈѕРѓгТЙХЛёу▓джЌєЬЂёТ║ђжѕЦ?жљетІГтИђжЉИтХЁТхЌуђ╣Уѕх№╝јжЈІТЦђтЈЋжЇЦЬЁеу┤ЮжЇФЬЂєлъ жѕЦТ╗ЃТ┤ЊуђЏ№йЁуќѓжњўт┐ЊТ╣┤жѕЦТ┐Њу┤њжЈёсЃЦтй▓жј║сѕА№╝јжЈІТЦЁтЎ╣жЉ║СЙ┐РѓгСйИЬў┤жЉ│С╗ІС╝ЕжЈєТѕЮТЃЏтДўЛЂРѓгСй║ЬЮљуњДт┐Њую░жЈІТЦђТЋќжЈїТЊёу┤ЮжЇљЬёђЬёюжЈЄуБІтЁўТХЊРѓгТЙХтГўтбАТЮЕТХЎуЂёте┤уЃйТ┤ЕжЇўуЄѓу┤ЮжЇдсёЦт┤ЋжЇЌТЦЂТИХТЙХЛёу▓джЌєЬЂёТ║ђТхБТњ╗уЇЎ жѕЦТ╗ѕТ┤ЕТХЊтЕЄЬЌБТц╣ТЅ│Рѓг?жљетІФтЪАтЕхРѓгжієтѓЮтџюжљњтЅЂтЪЇТ┐ѓтђЪРѓгтЉФРѓгСй╣у▓джЌєЬЂётйѓжљЉЛЃт╝ИжѕЦ№И╣Рѓг?ТХЊтХЁТѓЊуђЏ№йѕтдГжЈЅсЃ»у┤Южќ«тђЪтЁўжЈђТЃ░т╣ЈТХЊТњ│уЮўУ╣ЄЬѓАу«░жћЮ?,'жЈЃтЉ«уѕХжЈђУЇцТџљ',NULL,2,17,0,'published','2025-10-19 05:31:00','2025-10-19 05:31:00','2025-10-19 05:31:00',NULL,'manual'),(12,'жієтЕѓтъхжЇљЬёЃУЇАТХЊРѓгжЇд?жѕЦТ╗ёЬЋфжѕЦ?Т┐ѓТѕњу«Бу╗Й№И╝у┤њтДітЉ░тД│уЂъжЂЇЬЌЊжЈЁЬѕџт░»жћЏТ░гтїЌтДўу┐ауХћжфъТЏфу┤ЮуђхТјЊЬЋфт»░тЉ«ТќЂжћЏт▓Ѓуў▓жј░т┐ЊРѓгтЁ╝тф║тЕіРўЁуХќжіє?,'','ТхБТ╗ђУ┤ЪжЇЦУЌЅЬєЇ 4A у╗ЙЛёТФЎжЇќуї┤у┤ЮтДітЉ░тД│уЂъжЂЇЬЌЊжЈЁЬѕџт░»Тха?жѕЦТ╗ЃтїЌтДўт»ИЬЮЁТХЊ?+ уЉЌтъ«т┤АуњДт┐ћЬЋфжЉ│Т╗ЃТ╣┤жѕЦ?жњЂТЦЃлъжієтѓџуХІТХЊтгФТцѓжЉ║тѓду┤ЮуЂъжЂЇТБ┐тДітЉ«уЂётДЮ№йЅтј║жќ░УиеТйЃ жѕЦТ╗ЃтЂЏТЦасёДтћцжЈђжћ»Рѓг?жљетІгТ░«тЕЋЬѓгу┤ЮуЂъУЙеТїЅТхюТѕдТхўТХЊт║бТ╣ежЉ│ЛёЬЋфУц░тЈўТ░ду╝ЂтЏиу┤Юуђ╣ТХўЬЏДТЙХРЋЃтіДтДўТЮЉРЁижљбУ»▓тхјжієтѓЏТБцуњЂуЃўТДИжј╗ТёгтбажЈЅсЃеУЇА жѕЦТ╗ЃуўетДітЉгу«Бу╗Й№И╣РѓгТ┐Њу┤ЮТЮЕТе╗ТДИтЕЋЬѓБуѕХуЂъжЂЇТБ┐жЇџтЉітЊђте▓ТЦётЂцжћЏт▓ётЁўжЉ│тђЪлњжќ┐СйИтЈџжљЕТе╗ТїЅжЇњТ┐єтЋ▓жљЎЬёЂТ╣ЂжљетІ«уў▓жј░т┐југїжЈЅТЃДу┤▒жћЮ?,'жЈЁЬѕютЂБжј║сёет┤ў',NULL,1,12,2,'published','2025-10-19 05:31:38','2025-10-19 05:31:38','2025-10-19 05:31:38',NULL,'manual'),(14,'жЇљЬёђЬёюТХЊтЕџЬЋйте▓У»▓тДЕжћЏ?025 жфъ?12 жЈѕ?- 2026 жфъ?3 жЈѕтагу┤џ','тДітЉ░тД│уЂътЇъТхЌжЌётЉ«у▓джЌєЬЂёЬёюжћЏ?2 жЈѕ?16 жЈЃ?- 3 жЈѕ?31 жЈЃсЃ»у┤џ\nжЌєЬЂѕС║ЙжЇЌтЏЕжфЄжћЏТ░ГТЪіТЙД?100 у╗Фтє▓т┤ЪжЈЅтъ«тЈЋжЇЦЬЁеу┤ЮжЇњТ┐ёРѓгСйиУЁЉжієСЙђуЈ«у╗ЙЛЄС║Йжќ░тХЁЬўгТХЊТњ▓угЪжЈЂТгЉу▓їжЇЦсѕцТДджћЏт▒ЙтйЂТИџ?1 уђх?1 жЈЂТгЈЬёЪжієС┐ЊnТЙХТ╗ѕТБ┐жљЎтѓЏЬѓйжћЏТ░ГуўАжЇЏсёцу░▓жієСйИтЈџжЇЎтЕЃТДгжЉ║тѓЏТ╣АжЌѓТЮЉу┤ЉжЈђ?жѕЦТ╗ёЬЮежЇДРђ│Тй»Т┐ѓтЏДЬЏЙТЙХТ║ЙРѓгТ┐Њу┤ЮжЌєЬЂёТ║ђжљЈЬѕџтјюу╗ЅРѓг + жЌєЬЂёТ╣┤жЪФ№╣Ђт╝ђжћЏт▒йЬЎЂжЇдУЎ╣сѓе 128 жЇЈтє┐у┤ЎжЇџЬѓцтѓежќгТЊёу┤џжієС┐ЊnжЇдТЮ┐уЁЎТх╝Те╗тёгжћЏТ░гу«ЇТХЊТ╗ЁТИижієСйИсЂЄТЮЕуѓ▓уФХжЇЎтЕѓТЄєТЮѕжђЏу░▓жЇЕт║Аую│тДўТѕЮтџЪжЪгЬѓАтћцуњЄСйижЪЕжЌѓсёДсѓе 8 жјХТЕѕу┤ЮжЈЂТгЈугђжієСйИт░░жјХсѓёТ▒ЅжЇЏТе║тџЪуњЄСйиТгбжЇџт▒╝жЪЕТх╝Те╗тёгжіє?,'тДітЉ░тД│уЂътЇъТхЌжЌётЉ«у▓джЌєЬЂёЬёюжћЏ?2 жЈѕ?16 жЈЃ?- 3 жЈѕ?31 жЈЃсЃ»у┤џ\nжЌєЬЂѕС║ЙжЇЌтЏЕжфЄжћЏТ░ГТЪіТЙД?100 у╗Фтє▓т┤ЪжЈЅтъ«тЈЋжЇЦЬЁеу┤ЮжЇњТ┐ёРѓгСйиУЁЉжієСЙђуЈ«у╗ЙЛЄС║Йжќ░тХЁЬўгТХЊТњ▓угЪжЈЂТгЉу▓їжЇЦсѕцТДджћЏт▒ЙтйЂТИџ?1 уђх?1 жЈЂТгЈЬёЪжієС┐ЊnТЙХТ╗ѕТБ┐жљЎтѓЏЬѓйжћЏТ░ГуўАжЇЏсёцу░▓жієСйИтЈџжЇЎтЕЃТДгжЉ║тѓЏТ╣АжЌѓТЮЉу┤ЉжЈђ?жѕЦТ╗ёЬЮежЇДРђ│Тй»Т┐ѓтЏДЬЏЙТЙХТ║ЙРѓгТ┐Њу┤ЮжЌєЬЂёТ║ђжљЈЬѕџтјюу╗ЅРѓг + жЌєЬЂёТ╣┤жЪФ№╣Ђт╝ђжћЏт▒йЬЎЂжЇдУЎ╣сѓе 128 жЇЈтє┐у┤ЎжЇџЬѓцтѓежќгТЊёу┤џжієС┐ЊnжЇдТЮ┐уЁЎТх╝Те╗тёгжћЏТ░гу«ЇТХЊТ╗ЁТИижієСйИсЂЄТЮЕуѓ▓уФХжЇЎтЕѓТЄєТЮѕжђЏу░▓жЇЕт║Аую│тДўТѕЮтџЪжЪгЬѓАтћцуњЄСйижЪЕжЌѓсёДсѓе 8 жјХТЕѕу┤ЮжЈЂТгЈугђжієСйИт░░жјХсѓёТ▒ЅжЇЏТе║тџЪуњЄСйиТгбжЇџт▒╝жЪЕТх╝Те╗тёгжіє?,'event','[\"https://smarttourism717.oss-cn-beijing.aliyuncs.com/files/12/202510/1760962781355.jpg\"]',1,12,1,'published','2025-