INSERT INTO `scenic_reviews` (`id`, `user_id`, `scenic_id`, `rating`, `content`, `images`, `tags`, `visit_date`, `likes`, `sentiment`, `status`, `created_at`, `updated_at`, `deleted_at`) VALUES (2,4,1,5,'те┤тгГуў»2',NULL,'[\"жјгЛѓуј»тДБТЌѕуЈ«\", \"жЇіуЁјуи▒жј║сёет┤ў\", \"жЈѕтХЁтДЪТ┐ѓухЊ", \"ТцІт║бТФЎТх╝Те╝уие\", \"ТхюсѓЅРѓгТ░ФуЕХжЇњРђљ"]','2025-10-18',0,'positive','published','2025-10-18 13:49:07','2025-10-18 13:49:07',NULL),(3,12,1,5,'666',NULL,'[\"ТцІт║бТФЎТх╝Те╝уие\", \"жјгЛѓуј»тДБТЌѕуЈ«\", \"жЇіуЁјуи▒жј║сёет┤ў\", \"жЈѕтХЁтДЪТ┐ѓухЊ", \"ТхюсѓЅРѓгТ░ФуЕХжЇњРђљ"]','2025-10-18',0,'positive','deleted','2025-10-18 13:57:51','2025-10-18 13:57:51',NULL),(4,4,1,5,'те┤тгГуў»','[]','[\"ТцІт║бТФЎТх╝Те╝уие\", \"у╗їуЃўуџхтеЊтЉ«ТЪі\", \"жЈѕтХЁтДЪжЇЏсёЦтЪї\", \"ТхюсѓЅРѓгТ░ФуЕХжЇњРђљ", \"уњЂуѓгТЪдуђ╣т▒йТЮй\"]','2025-10-18',0,'positive','published','2025-10-18 20:10:00','2025-10-18 20:10:00',NULL),(5,9,1,5,'ТхБТњ╗уЇЎТХЊтХЅТЋі','[\"https://smarttourism717.oss-cn-beijing.aliyuncs.com/reviews/9/cab9574a-edc0-4dca-8728-3bfb9cb05c25.jpg\"]','[\"ТцІт║бТФЎТх╝Те╝уие\", \"у╗їуЃўуџхтеЊтЉ«ТЪі\", \"жЈѕтХЁтДЪжЇЏсёЦтЪї\", \"ТхюсѓЅРѓгТ░ФуЕХжЇњРђљ", \"уњЂуѓгТЪдуђ╣т▒йТЮй\"]','2025-10-18',0,'positive','published','2025-10-18 20:15:05','2025-10-18 20:15:05',NULL),(6,4,1,5,'ТхБТњ╗уЇЎТХЊтХЅТЋіжЇЮ?!!','[\"https://smarttourism717.oss-cn-beijing.aliyuncs.com/reviews/4/f02942fb-503d-4caf-9965-bad9700257c7.jpg\"]','[\"ТцІт║бТФЎТх╝Те╝уие\", \"жЈѕтХЁтДЪжЇЏсёЦтЪї\"]','2025-10-20',0,'positive','published','2025-10-20 20:21:22','2025-10-20 20:21:22',NULL),(7,4,1,5,'ТхБТњ╗уЇЎт»░таЮсѓй','[\"https://smarttourism717.oss-cn-beijing.aliyuncs.com/reviews/4/c8fa3597-3b93-48b5-b9ed-89567b17816f.jpg\"]','[\"ТцІт║бТФЎТх╝Те╝уие\", \"жЈѕтХЁтДЪжЇЏсёЦтЪї\", \"у╗їуЃўуџхтеЊтЉ«ТЪі\", \"ТхюсѓЅРѓгТ░ФуЕХжЇњРђљ"]','2025-10-20',0,'positive','published','2025-10-20 20:47:44','2025-10-20 20:47:44',NULL),(8,4,1,5,'ТхБТњ╗уЇЎТХЊтХЅТЋіжЇЮ?!!','[\"https://smarttourism717.oss-cn-beijing.aliyuncs.com/reviews/4/9d461d1b-bf46-4ab4-973b-94a49de9d