DROP TABLE IF EXISTS `scenic_spots`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `scenic_spots` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT 'жЈЁЬѕџт░»ID',
  `spot_code` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'жЈЁЬѕџт░»у╝ѓТаФуѕю',
  `name` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'жЈЁЬѕџт░»жЇџтХЄлъ',
  `city` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT 'жЇЈЬЁаТ┤ЈтДў? COMMENT 'жјхРѓгуЂъуѓ▓уЁёућ»?,
  `category` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'жЈЁЬѕџт░»жЇњтЌЎУбФ',
  `level` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'жЈЁЬѕџт░»у╗ЏтцїжфЄ',
  `address` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'уњЄ№ИЙу▓ЈжЇдТЮ┐ТйЃ',
  `description` text COLLATE utf8mb4_unicode_ci COMMENT 'у╗аРѓгжљГЬЁЪт╝┐ТЮЕ?,
  `full_description` text COLLATE utf8mb4_unicode_ci COMMENT 'уњЄ№ИЙу▓Јжј╗т┐џтаф',
  `image_url` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'ТХЊУ»▓ТхўURL',
  `map_image` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'жЇдТЮ┐ТхўжЇЦтЅДтбќURL',
  `latitude` decimal(10,7) DEFAULT NULL COMMENT 'у╗ЙЬёђт«│',
  `longitude` decimal(10,7) DEFAULT NULL COMMENT 'у╝Ђт┐Њт«│',
  `opening_hours` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'т»«РѓгжЈђуѓгТцѓжЌѓ?,
  `price` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'жЌѓсёДсѓеТхажћІуЅИ',
  `suggested_time` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'т»цжИ┐ЬєЁтеЊтЊЦтИ║жЈЃтаЋТџ▒',
  `max_capacity` int NOT NULL DEFAULT '10000' COMMENT 'жЈѕРѓгТЙХЛётБЎТЮъС╗ІтЎ║',
  `rating` decimal(2,1) NOT NULL DEFAULT '0.0' COMMENT 'уњЄтІФтъј',
  `favorites_count` int DEFAULT '0' COMMENT 'жЈђТЃ░ТБїжЈЂ?,
  `review_count` int NOT NULL DEFAULT '0' COMMENT 'уњЄтІфуј»жЈЂС╝┤тЎ║',
  `visit_count` int NOT NULL DEFAULT '0' COMMENT 'уњЂтЮЌТБХтеєРёЃТџЪ',
  `tags` json DEFAULT NULL COMMENT 'жЈЇтЏЕЬёижЈЂТЅ«у▓Ї',
  `status` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'ACTIVE' COMMENT 'жљўУѕхРѓгСЙіу┤░ACTIVE/MAINTENANCE/INACTIVE',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT 'жЇњТХўу╝ЊжЈЃтаЋТБ┐',
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT 'жЈЄтГўТЪіжЈЃтаЋТБ┐',
  `deleted_at` timestamp NULL DEFAULT NULL COMMENT 'ТЮъЬѕџтъ╣жЌёсѓєТцѓжЌѓ?,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_spot_code` (`spot_code`),
  KEY `idx_city` (`city`),
  KEY `idx_category` (`category`),
  KEY `idx_status` (`status`),
  KEY `idx_rating` (`rating`),
  KEY `idx_location` (`latitude`,`longitude`),
  KEY `idx_deleted_at` (`deleted_at`),
  KEY `idx_favorites_count` (`favorites_count` DESC)
) ENGINE=InnoDB AUTO_INCREMENT=6 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='жЈЁЬѕџт░»уљЏ?;
/*!40101 SET character_set_client = @saved_cs_client */;

