INSERT INTO `site_configs` (`id`, `config_key`, `config_json`, `created_at`, `updated_at`) VALUES (1,'landing','{\"stats\":[{\"id\":1,\"label\":\"ТБ░тІгуЦ┤жЇЉтЌЎРђўжљютў░",\"target\":96,\"suffix\":\"%\"},{\"id\":2,\"label\":\"уЉЋтЌЎТ┤іжЈЁЬѕџт░»\",\"target\":5,\"suffix\":\"+\"},{\"id\":3,\"label\":\"жфътє▓ТйјжЇЮтХЁу░▓\",\"target\":180,\"suffix\":\"ms\"}],\"features\":[{\"id\":1,\"icon\":\"ждЃТЋГ\",\"title\":\"жЈЁжИ┐тЁўуђ╣сѕАуЦдТБ░тІгуЦ┤\",\"description\":\"жЇЕУй░у░гLSTM-ARIMAтеБт│░Тѓјтд»Рђ│уђижћЏт▓ђу░┐жЇЉтЌЏЬЋЕте┤тгФТФЎжЇќуЃўТ╣ГжЈЅсЃЦЬЁ╣те┤СййуД╝жЇћуИЌ"},{\"id\":2,\"icon\":\"ждЃТцЄжћћт╗Ф",\"title\":\"уљЏт▓ђРќ╝уЉЎтІФтъЮ\",\"description\":\"AIу╗аТЦЂуАХТх╝Те║т»▓теЊТГїЬЮЇуњ║ЬѕютџјжћЏт▓ёС╝Ет»«РѓгТЦѓТе║тў▓жЉ║тѓюТИижЈЃтаЋТБ┐\"},{\"id\":3,\"icon\":\"ждЃТљ│\",\"title\":\"уђ╣уѓ┤ТцѓжЈЂуЅѕтхЂжЇњтЌўуђй\",\"description\":\"3DжЇЎЬѕЮЬЮІжЇќТаДсЂЄуЂът┐Цу┤Юуђ╣уѓ┤ТцѓжљЕТѕътИХжЈЁЬѕџт░»ТЮЕТё»ТЃђжљўУѕхРѓгС╣Ќ"}],\"highlights\":[{\"id\":1,\"badge\":\"жЇдТЮ┐уЁЎжќФтѓътјц\",\"title\":\"жЇЈЬЁаТ┤ЈтДўтГўТ╣░жЇдТЮ┐т»▓\",\"desc\":\"у╝ЂТњ│ТѓјжЇдТЮ┐Уѕ░тДўТќ┐Рѓг?жЉ║тѓџС║БжЈЃ?тДўТѕъТБїжЉ║тѓџу░Ау╗ЏтціТ╣фжЇдТЅ«тБњт»░Сййу╣ўуљЏт▒Й─ЂжЇетгГуџЪТх╝Тдј",\"points\":[\"жЅЂ?тДўТќ┐РѓгТгјугїуђЏ№йѕтдГжљЌуЉ░уиЏт«ИсЃДРќ╝\",\"жЅЂ?жЈЁЬѕџт░»жјхУЃ»ТхЄТХЊт║АтџГжЇЈсЃЦтйЏте┤СйИТѓю\",\"жЅЂ?жЈѕЬёђТ╣┤ТхюсѓЅРѓг?жЉ║тѓџу░АТхютгЕТгбтеЅсёЦтЈє\"]},{\"id\":2,\"badge\":\"AI ТБ░тІгуЦ┤\",\"title\":\"теБт│░ТѓјжЈЃУи║у░Гу╗аТЦЂуАХ\",\"desc\":\"LSTM Уё│ ARIMA жЇЎуі▓тДъжЇІтЏеТБЕТЙДуѓ▓ти▒жћЏт▓ђуЁГТХЊЬЁЪТ╣Ауђ╣сѕАуЦдуЊњтгфтеЇжЈЄт»ИКћ\",\"points\":[\"жЅЂ?96%+ ТЦат▓ЃуўЅжЌєтЌЌтЎ»у║ГЬєЙти╝жљЕЬєйуѕБ\",\"жЅЂ?уЂЈт┐ћуЅ▒жЈѕЬёђТ║ђжЈЁЬѕъуъЙтдФТјЊРѓгЛѓу┤ГжЇќТюХ",\"жЅЂ?ТБ░тІгуЦ┤жЇќТ┤фТБ┐ТХЊт║БуќєТиЄРђ│т«│ТЮѕТњ│тџГ\"]},{\"id\":3,\"badge\":\"3D жЇЎЬѕЮЬЮІжЇќТюХ",\"title\":\"теїтцІУ╣ѕт»«т┐ћТџЪжј╣Ьє╝сЂЄуЂът╗Ф",\"desc\":\"ТХЊтцїТи«жЇдТЮ┐ТхўТХЊт║АуќёжЈЃУѕхт»џжЈЇтЏфС╗ѕжЇћЬЪњу┤ЮжљЉЬЁатЂБ/жјисЃдт░ІжЇќУй░уФ┤жљЕЬє╗у░Ажљњуд▒",\"points\":[\"жЅЂ?жљЉЬЁатЂБжљЉЬЁътДЈ/ТхюуЃўуЦдТЮъсёеТіЌжЉ▒Тќ┐тДЕ\",\"жЅЂ?жЌЃтаЮРѓгтЦИЬЋЕуњђ№И┐угїтеЉтаЪС╝Ёжј║сёЕРѓгС╣Ќ",\"жЅЂ?ТЙХТ░▒у▓Њу╗ћЬѕЮтџюжќФтѓџу░▓уЂъТЏасЂџ\"]}],\"scenarios\":[{\"id\":1,\"icon\":\"ждЃТ«Й\",\"title\":\"ТЦѓТе║тў▓жќ┐ТгЈтў▓ТХЊт║АЬЄ▒те┤С╣Ќ",\"desc\":\"жЉ║тѓџС║БжЈЃсЃдтйЂжЇЊтХЅЬЋЕуњђ№╣ђУІЪТх╝Те║т»▓жЇЈсЃЦТ┤»жЈЃУѕхЬєїжћЏт▒йтЎ║уЂЈТѕътФбжЇФуцг"},{\"id\":2,\"icon\":\"ждЃТ«ъ\",\"title\":\"ТхюсѓЅРѓгТ░ГтИ┤Тц╣т┤Єу┤фжј║ТіЃ",\"desc\":\"ТБ░тІгуЦ┤уђ╣сѕАуЦдт«ёТІїУЃ║жћЏт▒йтДЕжјгСййуџЪжЈЂТЮЉтЈЋТхюсѓёугїжјйтЌўТх«ТЮъ№╣ѓЬЋХтеєЬЊб"},{\"id\":3,\"icon\":\"ждЃТ┤Южћћт╗Ф",\"title\":\"жјхУЃ»ТхЄТХЊт║АуЋежЇЈсёцу╣џжЌЁТи║",\"desc\":\"уЊњтЉ┤ТДЄжЇіуЁјуќёжЈЃУи║ТєАуњђ№И╝у┤ЮжЉ▒Тќ┐тДЕуђ╣тцЅу╣џТХЊт║Ау«ЇжјЙЬЁЪтйЂу╗ђу»Г"}],\"testimonials\":[{\"content\":\"ТБ░тІгуЦ┤у╝ЂТњ┤уЂЅжЇЕуЃўТ╣░уњљТЮЉТѓјуђ╣уѓ║Тф»жћЏт▒ЙтъюТхаЬёѓТ«ЉтеЊуе┐ЬЁ╣жјХТЏАуўћжљютЏеТДЉжЈётЈЦугЁжЌётХЃРѓгС┐Њ",\"author\":\"тДўТЮЉуЁёжЇЎсѓЅТЎБ\",\"role\":\"ТЮЕТё»ТЃђу╝Ђт┐ЋТѓі\"},{\"content\":\"ТЦѓТе║тў▓жЈЃтЅЂТ«Љжј║сЃЕРћЈТЮъ№╣ЂуиауњІтєет«│жЈЂтабти╝жј╗Тёгт┤їТхютЌЋугЅуЂЈТѕЎРѓгС┐Њ",\"author\":\"ућ»тѓЏТъЃжЈЃтЉГуюг\",\"role\":\"жЈЂуЅѕтхЂу╗ЅТЁГ"},{\"content\":\"уњ║ЬѕютџјуЉЎтІФтъЮуђхтйњС╝Ет»«Рѓгжј║ТјЌТДдт»░таЪТ╣Ђућ»Ьє╝тДфжћЏт▒ЙуѕХуђ╣ЬЮГуХІТЦат▒ЙТ┤┐Т┐ѓТѕњу░АжієС┐Њ",\"author\":\"жљютцјтъЌтдФЬєйуЂёжЇЈЬёђТ┤»\",\"role\":\"теЊуе┐ЬЁ╣жЈѕтХЁтДЪ\"}]}','2025-10-11 20:43:42','2025-11-05 15:17:21');
