CREATE TABLE `ticket_orders` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT 'уњЂсѕат┤ЪID',
  `order_no` varchar(50) NOT NULL COMMENT 'уњЂсѕат┤Ъу╝ѓТаДтй┐',
  `scenic_id` bigint NOT NULL COMMENT 'жЈЁЬѕџт░»ID',
  `scenic_name` varchar(100) DEFAULT NULL COMMENT 'жЈЁЬѕџт░»жЇџтХЄлъ',
  `user_id` bigint NOT NULL COMMENT 'жљбсёдтЪЏID',
  `user_name` varchar(50) DEFAULT NULL COMMENT 'жљбсёдтЪЏжЇџтХЄлъ',
  `user_phone` varchar(20) DEFAULT NULL COMMENT 'жљбсёдтЪЏжјхтгФТ║ђжЇЎ?,
  `ticket_type` varchar(20) NOT NULL COMMENT 'у╗ЂсёДЬЮњу╗ФУ»▓уђи: adult-жј┤ТёфТ▒Ѕу╗Ђ? child-жЇјУиеЬЂбу╗Ђ? student-уђЏ№ИЙТЋЊу╗Ђ? elder-жЉ░СйиТ▒Ѕу╗Ђ?,
  `ticket_count` int NOT NULL DEFAULT '1' COMMENT 'уњљЬЁасѓежЈЂС╝┤тЎ║',
  `unit_price` decimal(10,2) NOT NULL COMMENT 'жЇЌТЏџуј»жћЏтаЮтјЊжћЏ?,
  `total_amount` decimal(10,2) NOT NULL COMMENT 'жјгтЕџтЎЙТБ░Т┐Њу┤ЎжЇЈтє┐у┤џ',
  `visit_date` date NOT NULL COMMENT 'жЇЎтѓЮЬЮЄжЈЃсЃдТ╣А',
  `visitor_name` varchar(50) NOT NULL COMMENT 'теЊуе┐ЬЁ╣Т┐«Тњ│ТѓЋ',
  `visitor_phone` varchar(20) NOT NULL COMMENT 'теЊуе┐ЬЁ╣жЉ▒ТЌѓжЃ┤жљбСйЃуўй',
  `status` varchar(20) NOT NULL DEFAULT 'pending' COMMENT 'уњЂсѕат┤ЪжљўУѕхРѓг? pending-т»░тЉ«ТЋ«Тха? paid-т«ИтЈЅТЋ«Тха? used-т«ИУ╣ГтеЄжљб? cancelled-т«ИТЈњтйЄтеЉ? refunded-т«ИТЪЦРѓгРѓгтеє?,
  `payment_time` datetime DEFAULT NULL COMMENT 'жЈђЬѕЎу▓»жЈЃтаЋТБ┐',
  `used_time` datetime DEFAULT NULL COMMENT 'ТхБУиеТЋцжЈЃтаЋТБ┐жћЏтаЪуЅ│жќ┐РѓгжЈЃтаЋТБ┐жћЏ?,
  `cancelled_time` datetime DEFAULT NULL COMMENT 'жЇЎТаеуДижЈЃтаЋТБ┐',
  `refunded_time` datetime DEFAULT NULL COMMENT 'жќФРѓгтеєуѓгТцѓжЌѓ?,
  `remark` text COMMENT 'ТЙХтЏеТЋъ',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT 'жЇњТХўу╝ЊжЈЃтаЋТБ┐',
  `updated_at` datetime DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP COMMENT 'жЈЄтГўТЪіжЈЃтаЋТБ┐',
  `deleted` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'жЈёЬѕџТЃЂжЇњуі╗ТФј 0-жЈѕЬЂётъ╣жЌё?1-т«ИТЈњтъ╣жЌё?,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_order_no` (`order_no`),
  KEY `idx_scenic_id` (`scenic_id`),
  KEY `idx_user_id` (`user_id`),
  KEY `idx_status` (`status`),
  KEY `idx_visit_date` (`visit_date`),
  KEY `idx_created_at` (`created_at`)
) ENGINE=InnoDB AUTO_INCREMENT=11 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='жЌѓсёДсѓеуњЂсѕат┤ЪуљЏ?;
